In the following code, depending on whether you enable/disable either the display statement or dummy assignment, output waveform changes. I was wondering if there is an issue regarding how/when value of 'temp' is evaluated. Attached are module file, test file, sim_main.cpp and basic run script.



```


module m(
          output logic       test_ff,
          output logic [3:0] id,
          input  logic [3:0] external_id,
          input  logic       external_en,
          input  logic       clk,
          input  logic       rst         
          );

    logic                    data;
    logic [7:0]              counter;
    logic                    temp;
    logic                    temp2;

    always_ff @(posedge clk) begin
       if (rst)
         counter <= 0;
       else
         counter <= counter + 1;
    end

    assign data = (counter == 10);
    assign temp = (test_ff == 0) || (external_en && (external_id==id));

    always_ff @(posedge clk) begin
       if (rst)
         test_ff <= 0;
       else begin

// Un-comment either of the following lines to change the output seen in the waveform

//         temp2 <= temp;

//         $display("temp=%b\n", temp);

         if (temp)
            test_ff <= data;
       end
    end

    always_ff @(posedge clk) begin
       if ((test_ff == 0) || (external_en && (external_id==id)))
         id <= counter[3:0];
    end

endmodule

```
